import{_ as a,o as i,c as e,a1 as t}from"./chunks/framework.BmLW0N4k.js";const _=JSON.parse('{"title":"DLC01・灰の予言","description":"","frontmatter":{},"headers":[],"relativePath":"guide/dlc01-ashes-of-prophecy.md","filePath":"guide/dlc01-ashes-of-prophecy.md"}'),o={name:"guide/dlc01-ashes-of-prophecy.md"};function r(s,l,n,h,d,c){return i(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="dlc01・灰の予言" tabindex="-1">DLC01・灰の予言 <a class="header-anchor" href="#dlc01・灰の予言" aria-label="Permalink to &quot;DLC01・灰の予言&quot;">​</a></h1><h2 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h2><ul><li>Anno117内で <strong>最大級の火山島</strong>が登場し、定期的に噴火を起こす。</li><li>噴火によりラティウム全域に地震が発生し、建物に被害が出る。</li><li>火山島内にカエシリアの港が追加され、新アイテムが黒曜石と交換で入手できる。</li><li>火山ならではのイベントが多数追加されている。</li><li>新祭神「ウルカヌス」が追加。信仰4,000で<strong>炭鉱</strong>が解放される。</li></ul><h2 id="解放要素" tabindex="-1">解放要素 <a class="header-anchor" href="#解放要素" aria-label="Permalink to &quot;解放要素&quot;">​</a></h2><ul><li>生産品追加：<a href="/wiki/goods.html#latrunculi_sets">ラトルンクリ一式</a>・<a href="/wiki/goods.html#statuettes">小像</a>。</li><li>新素材 <strong>黒曜石</strong>：鉱山（スキル解放要）や採石場などからの副産物として生成される。</li><li>黒曜石は島ごとに埋蔵量が設定されており、掘り続けると枯渇する。</li><li>新スキルツリー「灰の予言」が解放される。</li></ul><h2 id="初期クエスト" tabindex="-1">初期クエスト <a class="header-anchor" href="#初期クエスト" aria-label="Permalink to &quot;初期クエスト&quot;">​</a></h2><ol><li>カエシリアから貢ぎ物イベントが発生する。</li><li>黒曜石を要求される。</li></ol><h2 id="火山イベント" tabindex="-1">火山イベント <a class="header-anchor" href="#火山イベント" aria-label="Permalink to &quot;火山イベント&quot;">​</a></h2><ol><li>定期的に地震が起こるようになり、建物が破壊される。（範囲はラティウム全土、島はランダム）</li><li>噴火するか沈静化するかはランダム。沈静化したら1.にループ。</li><li>噴火すると島全土に火山弾が降ってきて建物に被害が出る。（時間制：要検証）</li><li>軍事ユニットで住民の救出作業を行えば、1件当たり噴火時間が1分短縮される。（移動速度の速い<strong>騎兵</strong>が活躍）</li><li>噴火により火山弾が各地に落ちているが、回収すると<strong>黒曜石</strong>が入手できる。（海中のものは船で回収が必要）</li><li>噴火が落ち着くと、今度は噴煙により農作物・海産物の生産力が**50%**に低下する。（時間：要検証）</li><li>食料の生産力が大きく低下するため、在庫ストックは多めに確保しておくこと。</li><li>噴煙が晴れると土地の肥沃度が上昇し（噴火のたびに+10%）、農産物の生産力が+10%、火山性土LVが+1される。</li><li>火山性土LVの上限はスキルにより解放される。（初期値：3、最大値：5、肥沃度最大：+50%）</li><li>以降、1.へループ。</li></ol><p>2026年5月1日追加。</p>',10)])])}const p=a(o,[["render",r]]);export{_ as __pageData,p as default};
